let names = ["贺铸", "晁补之", "陈师道", "青幕子妇", "张耒", "侯蒙", "周邦彦", "陈瓘", "刘山老", "邵伯温", "净端", "李", "孔夷", "孔矩", "邹浩", "曾诞", "李坦然", "阮阅", "赵企", "汪存", "谢逸", "夏倪", "晁冲之", "苏庠", "祖可", "蔡", "张阁", "毛滂", "刘焘", "宇文元质", "范致虚", "郑少微", "李新", "欧阳辟", "司马", "王重", "某两地", "王采", "周纯", "曹希蕴", "廖刚", "赵鼎臣", "韩嘉彦", "谢薖", "沈蔚", "唐庚", "惠洪"]
let mock = {
    bool() {
        return async () => {
            return Math.random() > 0.5;
        }
    },
    code(minLen, maxLen) {
        let min = minLen || 10;
        let max = maxLen || min;
        let str = '0123456789ABCDEFGHIJKLMNOPQRSTUVWXYZ';
        return async () => {
            let len = Math.random() * (max - min) + min;
            let result = '';
            for (let i = len; i > 0; --i)
                result += str[Math.floor(Math.random() * str.length)];
            return result;
        }
    },
    name() {
        return async () => {
            let idx = Math.floor(Math.random() * names.length);
            return names[idx];
        }
    },
    char(minLen, maxLen) {
        let min = minLen || 10;
        let max = maxLen || min;
        return async () => {
            let len = Math.random() * (max - min) + min;
            let idx = Math.floor(Math.random() * words.length);
            let word = words[idx];
            return word.substring(0, Math.min(len, word.length));
        }
    },
    phone() {
        let nums = '0123456789';
        return async () => {
            let result = '13';
            for (let i = 9; i > 0; --i)
                result += nums[Math.floor(Math.random() * nums.length)];
            return result;
        }
    },
    int(min, max) {
        return async () => {
            let num = Math.random() * (max - min) + min;
            return Math.floor(num);
        }
    },
    float(min, max) {
        return async () => {
            let num = (Math.random() * (max - min) + min).toFixed(2);
            return Number(num);
        }
    },
    date: {
        pass(years, refDate) {
            return async () => {
                let date = new Date();
                if (typeof refDate !== "undefined") {
                    date = new Date(Date.parse(refDate));
                }
                let past = date.getTime();
                past -= await mock.int(1000, (years || 1) * 365 * 24 * 3600 * 1000)();
                date.setTime(past);
                return date.format('yyyy-MM-dd HH:mm:ss');
            }
        },
        future(years, refDate) {
            return async () => {
                let date = new Date();
                if (typeof refDate !== "undefined") {
                    date = new Date(Date.parse(refDate));
                }
                let future = date.getTime();
                future += await mock.int(1000, (years || 1) * 365 * 24 * 3600 * 1000)();
                date.setTime(future);
                return date.format('yyyy-MM-dd HH:mm:ss');
            }
        },
        between(from, to) {
            return async () => {
                let fromMilli = Date.parse(from);
                let dateOffset = await mock.int(0, Date.parse(to) - fromMilli)();
                let newDate = new Date(fromMilli + dateOffset);
                return newDate.format('yyyy-MM-dd HH:mm:ss');
            }
        }
    },
    select(opt) {
        if ($.isPlainObject(opt)) {
            opt = Object.keys(opt);
        }
        return async () => {
            if (Array.isArray(opt)) {
                let idx = Math.floor(Math.random() * opt.length);
                return opt[idx];
            }
            return opt;
        }
    },
    m2o(field) {
        return async () => {
            let autoSelect = field.autoSelect;
            field.autoSelect = function (values) {
                if (values.length > 0) {
                    let item = values[Math.floor(Math.random() * values.length)];
                    field.setValue([item[field.valueField], item[field.displayField]]);
                }
            }
            field.lookup();
            await sleep(100);
            field.autoSelect = autoSelect;
            return field.getValue();
        }
    },
    tags() {

    }
};

function sleep(time) {
    return new Promise((resolve) => setTimeout(resolve, time));
}

function wait(time) {
    return async () => {
        await sleep(time || 10);
    }
}

function click(el) {
    return async () => {
        $(el).click();
    }
}

function repeat(times, action) {
    return async () => {
        for (let i = 0; i < times; i++) {
            if (Array.isArray(action)) {
                for (let a of action) {
                    await a();
                }
            } else {
                await action();
            }
        }
    }
}

async function input(form, data) {
    let fields = Object.keys(data);
    for (let i = 0; i < fields.length; i++) {
        let field = fields[i];
        let editor = form.editors[field];
        if (editor) {
            let value = await data[field]();
            form.editors[field].setValue(value);
        } else {
            console.warn(field + '不存在')
        }
        await sleep(10);
    }
}

async function test(repeat, steps) {
    for (let i = 0; i < repeat; i++) {
        for (let step of steps) {
            await step();
        }
    }
}

jmaa.define("JTest", {
    steps() {
        return []
    },
    async run(repeat) {
        let me = this;
        for (let i = 0; i < repeat; i++) {
            for (let step of me.steps()) {
                await step();
            }
            console.log('ok');
        }
    }
})

jmaa.test = function (define) {
    if (typeof define === 'function') {
        define = define();
    }
    define.extends = 'JTest';
    define.xtype = 'JTest';
    return jmaa.define('JTest', define);
}

